export type IVXProviderName = 'ivx_ai_gateway' | 'openai_direct' | 'anthropic_direct';
export type IVXProviderFailureClass =
  | 'auth'
  | 'quota'
  | 'rate_limit'
  | 'timeout'
  | 'network'
  | 'bad_request'
  | 'server_error'
  | 'unknown';

export type IVXProviderStatus = {
  name: IVXProviderName;
  role: 'primary' | 'fallback';
  configured: boolean;
